import type { FC } from 'react';
import { cn } from '@/lib/utils';
import { type IconProps, type SvgProps, sizeMap } from '../../types';

export type ShowImportStatementsProps = IconProps;

const ShowImportStatementsLight: FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title ? <title>{title}</title> : null}
    <rect x="7" y="2" width="2" height="2" rx="1" fill="#6C707E" />
    <rect x="8" y="6" width="1" height="8" rx=".5" fill="#6C707E" />
    <rect x="5" y="6" width="4" height="1" rx=".5" fill="#6C707E" />
    <rect x="4" y="13" width="8" height="1" rx=".5" fill="#6C707E" />
  </svg>
);

const ShowImportStatementsDark: FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title ? <title>{title}</title> : null}
    <rect x="7" y="2" width="2" height="2" rx="1" fill="#CED0D6" />
    <rect x="8" y="6" width="1" height="8" rx=".5" fill="#CED0D6" />
    <rect x="5" y="6" width="4" height="1" rx=".5" fill="#CED0D6" />
    <rect x="4" y="13" width="8" height="1" rx=".5" fill="#CED0D6" />
  </svg>
);

export const ShowImportStatements: FC<ShowImportStatementsProps> = ({
  size = 'md',
  mode = 'light',
  className,
  'aria-label': ariaLabel,
  title,
  ...props
}) => {
  const SvgComponent =
    mode === 'light' ? ShowImportStatementsLight : ShowImportStatementsDark;

  return (
    <SvgComponent
      size={sizeMap[size]}
      className={cn('inline-block flex-shrink-0', className)}
      title={title}
      role={ariaLabel ? 'img' : 'presentation'}
      aria-label={ariaLabel}
      aria-hidden={!ariaLabel}
      {...props}
    />
  );
};
